import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import { ToggleSwitch } from './ToggleSwitch';

describe('ToggleSwitch', () => {
  it('renders in off state by default', () => {
    render(<ToggleSwitch />);
    expect(screen.getByTestId('toggle')).toHaveAttribute('aria-checked', 'false');
  });

  it('toggles to on when clicked', () => {
    render(<ToggleSwitch />);
    fireEvent.click(screen.getByTestId('toggle'));
    expect(screen.getByTestId('toggle')).toHaveAttribute('aria-checked', 'true');
  });

  it('toggles back to off on second click', () => {
    render(<ToggleSwitch />);
    const toggle = screen.getByTestId('toggle');
    fireEvent.click(toggle);
    fireEvent.click(toggle);
    expect(toggle).toHaveAttribute('aria-checked', 'false');
  });

  it('calls onChange with the new value', () => {
    const spy = jest.fn();
    render(<ToggleSwitch onChange={spy} />);
    fireEvent.click(screen.getByTestId('toggle'));
    expect(spy).toHaveBeenCalledWith(true);
    fireEvent.click(screen.getByTestId('toggle'));
    expect(spy).toHaveBeenCalledWith(false);
  });

  it('respects defaultOn prop', () => {
    render(<ToggleSwitch defaultOn />);
    expect(screen.getByTestId('toggle')).toHaveAttribute('aria-checked', 'true');
  });

  it('has correct switch role', () => {
    render(<ToggleSwitch />);
    expect(screen.getByRole('switch')).toBeInTheDocument();
  });
});

